------------------
---- MONITORS ----
------------------
 
hl.monitor({
    output   = "DP-1",
    mode     = "1920x1080@165.00",
    position = "0x0",
    scale    = "auto",
})
hl.monitor({
    output   = "HDMI-A-1",
    mode     = "1920x1080@60.00",
    position = "1920x0",
    scale    = "auto",
})

hl.dsp.exec_cmd("hyprctl dispatch moveworkspacetomonitor 1 DP-1")
hl.dsp.exec_cmd("hyprctl dispatch moveworkspacetomonitor 2 HDMI-A-1")
---------------------
---- MY PROGRAMS ----
---------------------
 
local terminal    = "kitty"
local fileManager = "dolphin"
local menu        = "rofi -show drun"
 
 
-------------------
---- AUTOSTART ----
-------------------
 
hl.on("hyprland.start", function()
  hl.exec_cmd("systemctl --user start graphical-session.target")
end)
-- in startup/init section
hl.dsp.exec_cmd("[workspace 2 silent] firefox")
hl.dsp.exec_cmd("[workspace 1 silent] vesktop")
hl.dsp.exec_cmd("[workspace 3 silent] feishin")
